function formatDuration(seconds) {
  return `${Math.round(seconds / 60)} min`;
}

// Builds the route view for either direction: matchKey is 'fromZone' when a hazard zone was
// clicked (shows that zone's route to all 4 shelters — here "fastest shelter" is a real
// priority worth highlighting thick+starred, with the other 3 as thin dashed alternates)
// or 'toShelter' when a shelter was clicked (shows that shelter's route to both hazard
// zones — there's no "alternate" framing here, both zones are equally worth knowing
// about, so equalPriority renders both routes thick with no star).
function buildRouteView(matchKey, matchValue, { equalPriority = false } = {}) {
  const matches = ROUTE_DATA.filter((r) => r[matchKey] === matchValue);
  const minDuration = Math.min(...matches.map((r) => r.duration));

  const lineFeatures = [];
  const labelFeatures = [];
  matches.forEach((r) => {
    const isNearest = equalPriority || r.duration === minDuration;
    const showStar = !equalPriority && isNearest;
    lineFeatures.push({
      type: 'Feature',
      properties: { fromZone: r.fromZone, toShelter: r.toShelter, distance: r.distance, duration: r.duration, isNearest },
      geometry: { type: 'LineString', coordinates: r.coords }
    });
    const midpoint = turf.along(turf.lineString(r.coords), r.distance / 2000, { units: 'kilometers' });
    labelFeatures.push({
      type: 'Feature',
      properties: { fromZone: r.fromZone, toShelter: r.toShelter, isNearest, label: (showStar ? '★ ' : '') + formatDuration(r.duration) },
      geometry: midpoint.geometry
    });
  });

  return {
    lines: { type: 'FeatureCollection', features: lineFeatures },
    labels: { type: 'FeatureCollection', features: labelFeatures }
  };
}

function showRoutes(matchKey, matchValue, options) {
  const view = buildRouteView(matchKey, matchValue, options);
  map.getSource('evac-routes').setData(view.lines);
  map.getSource('evac-route-labels').setData(view.labels);
}

function showRoutesForZone(zoneId) {
  showRoutes('fromZone', zoneId);
}

function showRoutesForShelter(shelterId) {
  showRoutes('toShelter', shelterId, { equalPriority: true });
}

const markersGeoJSON = {
  type: 'FeatureCollection',
  features: [
    { type: 'Feature', properties: { zoneId: 'zoneA', label: 'A', kind: 'no-go' }, geometry: { type: 'Point', coordinates: zoneAMarkerPoint } },
    { type: 'Feature', properties: { zoneId: 'zoneB', label: 'B', kind: 'no-go' }, geometry: { type: 'Point', coordinates: zoneBMarkerPoint } },
    { type: 'Feature', properties: { zoneId: 'safe', label: 'S', kind: 'safe' }, geometry: { type: 'Point', coordinates: safeMarkerPoint } },
    { type: 'Feature', properties: { zoneId: 'safeVivoCity', label: 'S', kind: 'safe' }, geometry: { type: 'Point', coordinates: vivoCityMarkerPoint } },
    { type: 'Feature', properties: { zoneId: 'safeStadium', label: 'S', kind: 'safe' }, geometry: { type: 'Point', coordinates: stadiumMarkerPoint } },
    { type: 'Feature', properties: { zoneId: 'safeKimSeng', label: 'S', kind: 'safe' }, geometry: { type: 'Point', coordinates: kimSengMarkerPoint } }
  ]
};

const map = new mapboxgl.Map({
  container: 'map',
  style: 'mapbox://styles/mapbox/dark-v11',
  center: [103.855, 1.29],
  zoom: 13.3
});

let activePopup = null;

function setActiveRow(zoneId) {
  const list = document.getElementById('zone-list');
  list.querySelectorAll('.zone-row').forEach((row) => {
    const isActive = row.dataset.zoneId === zoneId;
    row.classList.toggle('active', isActive);
    if (isActive) row.setAttribute('aria-current', 'true');
    else row.removeAttribute('aria-current');
  });
}

function openZonePopup(zoneId) {
  const zone = ZONES.find((z) => z.id === zoneId);
  if (!zone) return;

  if (activePopup) activePopup.remove();

  setActiveRow(zoneId);
  if (zone.status === 'no-go') showRoutesForZone(zoneId);
  else if (zone.status === 'safe') showRoutesForShelter(zoneId);

  activePopup = new mapboxgl.Popup({ offset: 14, className: `popup-${zone.status}` })
    .setLngLat(zone.point)
    .setHTML(`
      <div class="popup-title">${zone.name}</div>
      <div class="popup-status ${zone.status}">${ZONE_STATUS_LABELS[zone.status]}</div>
      <div class="popup-body">${zone.instruction}</div>
    `)
    .addTo(map);
}

function hazardRowHTML(zone) {
  const pill = `<span class="row-pill ${zone.status}">${ZONE_STATUS_LABELS[zone.status]}</span>`;
  return `
    <div class="zone-row ${zone.type}" tabindex="0" role="button" data-zone-id="${zone.id}">
      <span class="zone-chip ${zone.type}"></span>
      <span class="zone-text">
        <span class="zone-name">${zone.name}${pill}</span>
        <span class="zone-desc">${zone.desc}</span>
      </span>
    </div>
  `;
}

function shelterRowHTML(zone) {
  return `
    <div class="zone-row safe" tabindex="0" role="button" data-zone-id="${zone.id}">
      <span class="zone-chip safe"></span>
      <span class="zone-text">
        <span class="zone-name" title="${zone.short}">${zone.short}</span>
        <span class="zone-desc">${zone.desc}</span>
      </span>
      <span class="zone-capacity">${zone.capacity}</span>
    </div>
  `;
}

function renderZoneList() {
  const list = document.getElementById('zone-list');
  const hazards = ZONES.filter((z) => z.status === 'no-go' || z.status === 'caution');
  const shelters = ZONES.filter((z) => z.status === 'safe');

  list.innerHTML = `
    <div class="section-label">Active Hazards</div>
    ${hazards.map(hazardRowHTML).join('')}
    <div class="section-label">Shelters &middot; ${shelters.length} Open</div>
    ${shelters.map(shelterRowHTML).join('')}
  `;

  const noGoCount = ZONES.filter((z) => z.status === 'no-go').length;
  document.getElementById('panel-summary').textContent = `${noGoCount} hazards · ${shelters.length} shelters open`;

  list.querySelectorAll('.zone-row').forEach((row) => {
    const flyToZone = () => {
      const zone = ZONES.find((z) => z.id === row.dataset.zoneId);
      map.flyTo({ center: zone.point, zoom: 15 });
      openZonePopup(zone.id);
    };
    row.addEventListener('click', flyToZone);
    row.addEventListener('keydown', (e) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        flyToZone();
      }
    });
  });
}

function startTicker() {
  const tapeText = document.getElementById('tape-text');
  const advisories = ZONES.map((z) => `${z.name.toUpperCase()} — ${z.desc.toUpperCase()}`);
  tapeText.textContent = advisories.join('   •   ') + '   •   ';

  const clock = document.getElementById('ticker-clock');
  const fmt = new Intl.DateTimeFormat('en-GB', {
    timeZone: 'Asia/Singapore',
    hour: '2-digit',
    minute: '2-digit'
  });
  const tick = () => {
    clock.textContent = `SGT ${fmt.format(new Date())}`;
  };
  tick();
  setInterval(tick, 30000);
}

map.on('load', () => {
  map.addSource('caution-zone', { type: 'geojson', data: cautionZoneGeoJSON });
  map.addSource('no-go-zones', { type: 'geojson', data: noGoZonesGeoJSON });
  map.addSource('safe-zone', { type: 'geojson', data: safeZoneGeoJSON });
  map.addSource('evac-routes', { type: 'geojson', data: { type: 'FeatureCollection', features: [] } });
  map.addSource('evac-route-labels', { type: 'geojson', data: { type: 'FeatureCollection', features: [] } });
  map.addSource('markers', { type: 'geojson', data: markersGeoJSON });

  map.addLayer({
    id: 'caution-fill',
    type: 'fill',
    source: 'caution-zone',
    paint: { 'fill-color': '#e2a33c', 'fill-opacity': 0.2 }
  });
  map.addLayer({
    id: 'caution-outline',
    type: 'line',
    source: 'caution-zone',
    paint: { 'line-color': '#e2a33c', 'line-width': 1.5, 'line-dasharray': [2, 2] }
  });

  map.addLayer({
    id: 'safe-fill',
    type: 'fill',
    source: 'safe-zone',
    paint: { 'fill-color': '#21976b', 'fill-opacity': 0.28 }
  });
  map.addLayer({
    id: 'safe-outline',
    type: 'line',
    source: 'safe-zone',
    paint: { 'line-color': '#21976b', 'line-width': 2 }
  });

  map.addLayer({
    id: 'no-go-fill',
    type: 'fill',
    source: 'no-go-zones',
    paint: { 'fill-color': '#d1293f', 'fill-opacity': 0.38 }
  });
  map.addLayer({
    id: 'no-go-outline',
    type: 'line',
    source: 'no-go-zones',
    paint: { 'line-color': '#d1293f', 'line-width': 2 }
  });

  // Alternate routes (thin, dashed, muted) — drawn first so the nearest route sits on top.
  map.addLayer({
    id: 'evac-route-alt',
    type: 'line',
    source: 'evac-routes',
    filter: ['==', ['get', 'isNearest'], false],
    paint: { 'line-color': '#eef2f1', 'line-width': 2, 'line-opacity': 0.45, 'line-dasharray': [2, 2] }
  });

  // Fastest route — thick, solid, full opacity. "isNearest" is recomputed for whichever
  // direction is showing (zone→shelters or shelter→zones), so this filter works for both.
  map.addLayer({
    id: 'evac-route-nearest',
    type: 'line',
    source: 'evac-routes',
    filter: ['==', ['get', 'isNearest'], true],
    paint: { 'line-color': '#eef2f1', 'line-width': 5, 'line-opacity': 1 }
  });

  map.addLayer({
    id: 'evac-route-labels',
    type: 'symbol',
    source: 'evac-route-labels',
    layout: {
      'text-field': ['get', 'label'],
      'text-font': ['Open Sans Bold', 'Arial Unicode MS Bold'],
      'text-size': ['case', ['get', 'isNearest'], 13, 11],
      'text-allow-overlap': true,
      'text-anchor': 'bottom'
    },
    paint: {
      'text-color': ['case', ['get', 'isNearest'], '#eef2f1', '#b7c1c8'],
      'text-halo-color': '#0a1420',
      'text-halo-width': 1.4
    }
  });

  map.addLayer({
    id: 'marker-circle',
    type: 'circle',
    source: 'markers',
    paint: {
      'circle-radius': 11,
      'circle-color': ['match', ['get', 'kind'], 'safe', '#21976b', '#d1293f'],
      'circle-stroke-color': '#eef2f1',
      'circle-stroke-width': 2
    }
  });
  map.addLayer({
    id: 'marker-label',
    type: 'symbol',
    source: 'markers',
    layout: {
      'text-field': ['get', 'label'],
      'text-font': ['Open Sans Bold', 'Arial Unicode MS Bold'],
      'text-size': 11,
      'text-allow-overlap': true
    },
    paint: { 'text-color': '#eef2f1' }
  });

  const clickableLayers = ['no-go-fill', 'safe-fill', 'caution-fill', 'marker-circle'];
  map.on('click', clickableLayers, (e) => {
    const zoneId = e.features[0].properties.zoneId;
    openZonePopup(zoneId);
  });

  clickableLayers.forEach((layerId) => {
    map.on('mouseenter', layerId, () => { map.getCanvas().style.cursor = 'pointer'; });
    map.on('mouseleave', layerId, () => { map.getCanvas().style.cursor = ''; });
  });

  renderZoneList();
  startTicker();
});
